const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER;

if (!SENDGRID_API_KEY || !TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN || !TWILIO_PHONE_NUMBER) {
  throw new Error('Missing required environment variables for email and SMS services');
}

sgMail.setApiKey(SENDGRID_API_KEY);

const client = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

exports.sendNotification = async (req, res) => {
  try {
    const { type, to, subject, text, html, message } = req.body;

    if (type === 'email') {
      const msg = {
        to,
        from: process.env.SENDGRID_FROM_EMAIL || 'noreply@yourapp.com',
        subject: subject || 'Notification',
        text: text || '',
        html: html || '',
      };

      await sgMail.send(msg);
      res.status(200).json({ success: true, message: 'Email sent successfully' });
    } else if (type === 'sms') {
      const smsMsg = {
        body: message || text || subject,
        to,
        from: TWILIO_PHONE_NUMBER,
      };

      await client.messages.create(smsMsg);
      res.status(200).json({ success: true, message: 'SMS sent successfully' });
    } else {
      res.status(400).json({ success: false, message: 'Invalid message type. Use "email" or "sms"' });
    }
  } catch (error) {
    console.error('Error sending notification:', error);
    res.status(500).json({ 
      success: false, 
      message: 'Failed to send notification',
      error: error.message 
    });
  }
};